function adminLicProveedorProviderHasInventory(providerRow) {
    if (!providerRow) return false;
    const structured = Array.isArray(providerRow.license_lines) ? providerRow.license_lines : [];
    if (
        structured.some(function (entry) {
            return entry && String(entry.cred || '').trim();
        })
    ) {
        return true;
    }
    if (
        String(providerRow.license_notes || '')
            .replace(/\r\n/g, '\n')
            .split('\n')
            .some(function (line) {
                return String(line).trim();
            })
    ) {
        return true;
    }
    if (adminLicProveedorSoldLinesFromProvider(providerRow).length > 0) return true;
    if (
        (providerRow.expired_lines || []).some(function (entry) {
            return entry && String(entry.cred || '').trim();
        })
    ) {
        return true;
    }
    if (
        (providerRow.suspended_lines || []).some(function (entry) {
            return entry && String(entry.cred || '').trim();
        })
    ) {
        return true;
    }
    return false;
}

function adminLicProveedorPanelUserLineCount(providerRow) {
    let total = adminLicProveedorVisibleLinesFromProvider(providerRow).length;
    total += adminLicProveedorSoldLinesFromProvider(providerRow).length;
    (providerRow.expired_lines || []).forEach(function (entry) {
        if (entry && String(entry.cred || '').trim()) total += 1;
    });
    (providerRow.suspended_lines || []).forEach(function (entry) {
        if (entry && String(entry.cred || '').trim()) total += 1;
    });
    return total;
}

function adminLicProveedorDisplayLabel(username) {
    const name = username != null && String(username).trim() !== '' ? String(username).trim() : '—';
    return 'Proveedor: ' + name;
}

