/** Abre modales al llegar desde Menú2 de otras plantillas (?open=…). Historial → Historial de Compra. */
function handleAdminLicenciasMenuDeepLink() {
    const params = new URLSearchParams(window.location.search);
    const open = (params.get('open') || '').trim().toLowerCase();
    if (!open) return;

    function stripOpenParam() {
        params.delete('open');
        const q = params.toString();
        const next = window.location.pathname + (q ? '?' + q : '') + (window.location.hash || '');
        window.history.replaceState({}, '', next);
    }

    function runAction() {
        if (open === 'historial') {
            window.location.href = '/tienda/historial_compras#purchaseHistoryLicenciasSection';
            return;
        } else if (open === 'gestionar-productos' && typeof showGestionarProductosModal === 'function') {
            showGestionarProductosModal();
        } else if (open === 'saldo-clientes' && typeof showSaldoClientesModal === 'function') {
            void showSaldoClientesModal();
        } else if (open === 'notificaciones' && typeof showAdminLicenciasNotificacionesModal === 'function') {
            showAdminLicenciasNotificacionesModal();
        } else if (open === 'proveedores-ventas' && typeof adminLicProveedorVentasOpenModal === 'function') {
            adminLicProveedorVentasOpenModal();
        } else if (open === 'renovar-dia') {
            const renewBtn = document.getElementById('btnEjecutarRenovacionDia');
            if (renewBtn && typeof adminLicenseRunDayRenewalManual === 'function') {
                void adminLicenseRunDayRenewalManual(renewBtn);
            }
        } else if (open === 'agregar-licencia' && typeof showAddLicenseModal === 'function') {
            void showAddLicenseModal();
        }
        stripOpenParam();
    }

    if (
        open === 'historial' ||
        open === 'gestionar-productos' ||
        open === 'saldo-clientes' ||
        open === 'notificaciones' ||
        open === 'proveedores-ventas' ||
        open === 'renovar-dia' ||
        open === 'agregar-licencia'
    ) {
        window.setTimeout(runAction, 600);
    }
}

function licenseWarrantyDaysUi(license) {
    if (!license) return 5;
    const v = license.warranty_days;
    const n = v != null && v !== '' ? Number(v) : 5;
    return Number.isFinite(n) && n >= 0 ? n : 5;
}

function licenseTermDaysUi(license) {
    if (!license) return 30;
    const v = license.license_term_days;
    const n = v != null && v !== '' ? Number(v) : 30;
    return Number.isFinite(n) && n >= 1 ? n : 30;
}

function licenseTermUiLabel(license) {
    if (license && license.term_ui_label) {
        return String(license.term_ui_label);
    }
    const days = licenseTermDaysUi(license);
    if (days === 30) return 'mes';
    if (days === 365) return '1 año';
    if (days === 730) return '2 años';
    if (days % 30 === 0 && days >= 60 && days <= 330) {
        return String(days / 30) + ' meses';
    }
    return String(days) + 'd';
}

